namespace sv_c95e35638853403eaf2bae9dd55a0cea.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

.settings-sidebar {
    width: 220px;
    min-height: 100%;
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.nav-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Profile</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading profile…</span>
        </div>
    }
    else
    {
        <div class="avatar-area mb-4">
            <label class="form-label fw-semibold">Avatar</label>
            <div class="d-flex align-items-center gap-3">
                <img src="@editAvatarUrl" alt="Avatar" class="avatar-image" />
                <code class="text-muted small text-break">@editAvatarUrl</code>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="editDisplayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="editEmail" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="editBio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveProfile" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
        </div>

        @if (successMessage is not null)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span>✓ @successMessage</span>
            </div>
        }
    }
</div>

@code {
    private UserProfile? savedProfile;
    private string editDisplayName = "";
    private string editEmail = "";
    private string editBio = "";
    private string editAvatarUrl = "";
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private CancellationTokenSource? toastCts;

    protected override async Task OnInitializedAsync()
    {
        savedProfile = await SettingsService.GetProfileAsync();
        LoadFromProfile(savedProfile);
        loading = false;
    }

    private void LoadFromProfile(UserProfile p)
    {
        editDisplayName = p.DisplayName;
        editEmail = p.Email;
        editBio = p.Bio;
        editAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        saving = true;
        var updated = new UserProfile(editDisplayName, editEmail, editAvatarUrl, editBio);
        await SettingsService.SaveProfileAsync(updated);
        savedProfile = updated;
        saving = false;
        await ShowSuccess("Profile saved successfully!");
    }

    private void DiscardChanges()
    {
        if (savedProfile is not null)
            LoadFromProfile(savedProfile);
        successMessage = null;
    }

    private async Task ShowSuccess(string message)
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        successMessage = message;
        var token = toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            successMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }
}

@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Notifications</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading preferences…</span>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Notification Channels</h6>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            <p class="text-muted small">Check a channel to mute it.</p>

            @foreach (var channel in availableChannels)
            {
                var isMuted = mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SavePreferences" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Preferences
            </button>
        </div>

        @if (successMessage is not null)
        {
            <div class="alert alert-success mt-3" role="alert">✓ @successMessage</div>
        }
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private CancellationTokenSource? toastCts;

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    private static readonly string[] availableChannels =
        ["General", "Announcements", "Engineering", "Marketing", "Support", "Random"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        saving = true;
        var prefs = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        saving = false;
        await ShowSuccess("Notification preferences saved!");
    }

    private async Task ShowSuccess(string message)
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        successMessage = message;
        var token = toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            successMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }
}

@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Security</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading security settings…</span>
        </div>
    }
    else
    {
        @* ── Change Password Panel ── *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <span class="fw-semibold">Change Password</span>
                <button class="btn btn-sm btn-outline-secondary"
                        @onclick="() => passwordPanelOpen = !passwordPanelOpen">
                    @(passwordPanelOpen ? "Collapse" : "Expand")
                </button>
            </div>

            @if (passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm Password</label>
                        <input type="password" class="form-control" @bind="confirmPassword" />
                    </div>

                    @if (passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@passwordError</div>
                    }
                    @if (passwordSuccess is not null)
                    {
                        <div class="alert alert-success py-2">✓ @passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@changingPassword">
                        @if (changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                    <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (lastPasswordChange.HasValue)
                    {
                        <small class="text-muted ms-3">
                            Last password change: @lastPasswordChange.Value.ToString("MMM dd, yyyy")
                        </small>
                    }
                </div>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@twoFactorEnabled"
                           @onchange="e => twoFactorEnabled = (bool)e.Value!" />
                </div>
            </div>
        </div>

        @* ── Active Sessions ── *@
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in sessions)
                        {
                            var isCurrent = session.Id == currentSessionId;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
