                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@revoking">
                                @if (revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool loading = true;

    // Password
    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordError;
    private string? passwordSuccess;
    private bool changingPassword;

    // 2FA
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;

    // Sessions
    private List<ActiveSession> sessions = [];
    private string? currentSessionId;
    private ActiveSession? sessionToRevoke;
    private bool revoking;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions.ToList();
        // Treat the most recently active session as the current one
        currentSessionId = sessions.OrderByDescending(s => s.LastActive).FirstOrDefault()?.Id;
        loading = false;
    }

    private async Task UpdatePassword()
    {
        passwordError = null;
        passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword) ||
            string.IsNullOrWhiteSpace(confirmPassword))
        {
            passwordError = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New password and confirmation do not match.";
            return;
        }

        changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            passwordSuccess = "Password updated successfully!";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
        finally
        {
            changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is null) return;

        revoking = true;
        await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
        sessions.RemoveAll(s => s.Id == sessionToRevoke.Id);
        sessionToRevoke = null;
        revoking = false;
    }
}

