                @* ── Language ── *@
                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Language</h6>
                    <select class="form-select" @bind="language">
                        @foreach (var lang in languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                @* ── Compact Mode ── *@
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@saving">
                    @if (saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>

                @if (successMessage is not null)
                {
                    <div class="alert alert-success mt-3" role="alert">✓ @successMessage</div>
                }
            </div>

            @* ── Live Preview ── *@
            <div class="col-md-6">
                <h6 class="fw-semibold mb-2">Preview</h6>
                <div class="preview-area @PreviewThemeClass" style="@PreviewFontStyle">
                    <div class="preview-header">
                        <strong>Dashboard</strong>
                    </div>
                    <div class="preview-body @(compactMode ? "compact" : "")">
                        <p class="preview-text">
                            This is a preview of your selected appearance settings.
                        </p>
                        <div class="preview-card">
                            <span class="preview-label">Theme:</span> @theme
                        </div>
                        <div class="preview-card">
                            <span class="preview-label">Font:</span> @fontSize
                        </div>
                        <div class="preview-card">
                            <span class="preview-label">Language:</span> @language
                        </div>
                        <div class="preview-card">
                            <span class="preview-label">Compact:</span> @(compactMode ? "On" : "Off")
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private CancellationTokenSource? toastCts;

    private string theme = "System";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewFontStyle => fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        loading = false;
    }

    private async Task SaveAppearance()
    {
        saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(theme, fontSize, language, compactMode));
        saving = false;
        await ShowSuccess("Appearance settings saved!");
    }

    private async Task ShowSuccess(string message)
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        successMessage = message;
        var token = toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            successMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }
}
"}

