@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Profile</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading profile…</span>
        </div>
    }
    else
    {
        <div class="avatar-area mb-4">
            <label class="form-label fw-semibold">Avatar</label>
            <div class="d-flex align-items-center gap-3">
                <img src="@editAvatarUrl" alt="Avatar" class="avatar-image" />
                <code class="text-muted small text-break">@editAvatarUrl</code>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="editDisplayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="editEmail" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="editBio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveProfile" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
        </div>

        @if (successMessage is not null)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span>✓ @successMessage</span>
            </div>
        }
    }
</div>

@code {
    private UserProfile? savedProfile;
    private string editDisplayName = "";
    private string editEmail = "";
    private string editBio = "";
    private string editAvatarUrl = "";
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private CancellationTokenSource? toastCts;

    protected override async Task OnInitializedAsync()
    {
        savedProfile = await SettingsService.GetProfileAsync();
        LoadFromProfile(savedProfile);
        loading = false;
    }

    private void LoadFromProfile(UserProfile p)
    {
        editDisplayName = p.DisplayName;
        editEmail = p.Email;
        editBio = p.Bio;
        editAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        saving = true;
        var updated = new UserProfile(editDisplayName, editEmail, editAvatarUrl, editBio);
        await SettingsService.SaveProfileAsync(updated);
        savedProfile = updated;
        saving = false;
        await ShowSuccess("Profile saved successfully!");
    }

    private void DiscardChanges()
    {
        if (savedProfile is not null)
            LoadFromProfile(savedProfile);
        successMessage = null;
    }

    private async Task ShowSuccess(string message)
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        successMessage = message;
        var token = toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            successMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }
}

