@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Notifications</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading preferences…</span>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Notification Channels</h6>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            <p class="text-muted small">Check a channel to mute it.</p>

            @foreach (var channel in availableChannels)
            {
                var isMuted = mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SavePreferences" disabled="@saving">
                @if (saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Preferences
            </button>
        </div>

        @if (successMessage is not null)
        {
            <div class="alert alert-success mt-3" role="alert">✓ @successMessage</div>
        }
    }
</div>

@code {
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private CancellationTokenSource? toastCts;

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    private static readonly string[] availableChannels =
        ["General", "Announcements", "Engineering", "Marketing", "Support", "Random"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        saving = true;
        var prefs = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        saving = false;
        await ShowSuccess("Notification preferences saved!");
    }

    private async Task ShowSuccess(string message)
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        successMessage = message;
        var token = toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            successMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }
}

