@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Security</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading security settings…</span>
        </div>
    }
    else
    {
        @* ── Change Password Panel ── *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <span class="fw-semibold">Change Password</span>
                <button class="btn btn-sm btn-outline-secondary"
                        @onclick="() => passwordPanelOpen = !passwordPanelOpen">
                    @(passwordPanelOpen ? "Collapse" : "Expand")
                </button>
            </div>

            @if (passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm Password</label>
                        <input type="password" class="form-control" @bind="confirmPassword" />
                    </div>

                    @if (passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@passwordError</div>
                    }
                    @if (passwordSuccess is not null)
                    {
                        <div class="alert alert-success py-2">✓ @passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@changingPassword">
                        @if (changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                    <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (lastPasswordChange.HasValue)
                    {
                        <small class="text-muted ms-3">
                            Last password change: @lastPasswordChange.Value.ToString("MMM dd, yyyy")
                        </small>
                    }
                </div>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@twoFactorEnabled"
                           @onchange="e => twoFactorEnabled = (bool)e.Value!" />
                </div>
            </div>
        </div>

        @* ── Active Sessions ── *@
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in sessions)
                        {
                            var isCurrent = session.Id == currentSessionId;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        @* ── Revoke Confirmation Dialog ── *@
        @if (sessionToRevoke is not null)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@sessionToRevoke.Device</strong> in
                                <strong>@sessionToRevoke.Location</strong>?
                            </p>
                            <p class="text-muted small">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@revoking">
                                @if (revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool loading = true;

    // Password
    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordError;
    private string? passwordSuccess;
    private bool changingPassword;

    // 2FA
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;

    // Sessions
    private List<ActiveSession> sessions = [];
    private string? currentSessionId;
    private ActiveSession? sessionToRevoke;
    private bool revoking;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions.ToList();
        // Treat the most recently active session as the current one
        currentSessionId = sessions.OrderByDescending(s => s.LastActive).FirstOrDefault()?.Id;
        loading = false;
    }

    private async Task UpdatePassword()
    {
        passwordError = null;
        passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword) ||
            string.IsNullOrWhiteSpace(confirmPassword))
        {
            passwordError = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New password and confirmation do not match.";
            return;
        }

        changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            passwordSuccess = "Password updated successfully!";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
        finally
        {
            changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is null) return;

        revoking = true;
        await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
        sessions.RemoveAll(s => s.Id == sessionToRevoke.Id);
        sessionToRevoke = null;
        revoking = false;
    }
}

