@using sv_c95e35638853403eaf2bae9dd55a0cea.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h3 class="section-title">Appearance</h3>

    @if (loading)
    {
        <div class="d-flex align-items-center gap-2 py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Loading appearance settings…</span>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                @* ── Theme ── *@
                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Theme</h6>
                    @foreach (var t in themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{t}")" value="@t"
                                   checked="@(theme == t)"
                                   @onchange="() => theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>

                @* ── Font Size ── *@
                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Font Size</h6>
                    @foreach (var s in fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{s}")" value="@s"
                                   checked="@(fontSize == s)"
                                   @onchange="() => fontSize = s" />
                            <label class="form-check-label" for="@($"fs-{s}")">@s</label>
                        </div>
                    }
                </div>

                @* ── Language ── *@
                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Language</h6>
                    <select class="form-select" @bind="language">
                        @foreach (var lang in languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                @* ── Compact Mode ── *@
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@saving">
                    @if (saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>

                @if (successMessage is not null)
                {
                    <div class="alert alert-success mt-3" role="alert">✓ @successMessage</div>
                }
            </div>

