            <div class="col-md-6">
                <h6 class="fw-semibold mb-2">Preview</h6>
                <div class="preview-area @PreviewThemeClass" style="@PreviewFontStyle">
                    <div class="preview-header">
                        <strong>Dashboard</strong>
                    </div>
                    <div class="preview-body @(compactMode ? "compact" : "")">
                        <p class="preview-text">
                            This is a preview of your selected appearance settings.
                        </p>
                        <div class="preview-card">
                            <span class="preview-label">Theme:</span> @theme
                        </div>
                        <div class="preview-card">
                            <span class="preview-label">Font:</span> @fontSize
                        </div>
                        <div class="preview-card">
                            <span class="preview-label">Language:</span> @language
                        </div>
                        <div class="preview-card">
                            <span class="preview-label">Compact:</span> @(compactMode ? "On" : "Off")
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
