@code {
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private CancellationTokenSource? toastCts;

    private string theme = "System";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewFontStyle => fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        loading = false;
    }

    private async Task SaveAppearance()
    {
        saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(theme, fontSize, language, compactMode));
        saving = false;
        await ShowSuccess("Appearance settings saved!");
    }

    private async Task ShowSuccess(string message)
    {
        toastCts?.Cancel();
        toastCts = new CancellationTokenSource();
        successMessage = message;
        var token = toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            successMessage = null;
            await InvokeAsync(StateHasChanged);
        }
        catch (TaskCanceledException) { }
    }
}

