arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="HandleSectionChanged" />

    <div class="settings-content">
        @switch (activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string activeSection = "Profile";

    private void HandleSectionChanged(string section)
    {
        activeSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    margin: -1.5rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.section-panel .section-title {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

.section-panel .avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="HandleSectionChanged" />

    <div class="settings-content">
        @switch (activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string activeSection = "Profile";

    private void HandleSectionChanged(string section)
    {
        activeSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    margin: -1.5rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.section-panel .section-title {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

.section-panel .avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

